"use client";

import React, { useEffect, useRef } from "react";
import Image from "next/image";
import Link from "next/link";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { MapPin } from "lucide-react";
import { Button } from "@/components/ui/Button";
import { useEvents } from "@/lib/hooks/public/useEventHooks";
import FormateDateTime from "@/components/formateDateTime/page";
import { EventType } from "@/lib/types/eventsType"; // Ensure this path matches your types file

gsap.registerPlugin(ScrollTrigger);

const Events = () => {
  const sectionRef = useRef<HTMLElement | null>(null);

  useEffect(() => {
    if (!sectionRef.current) return;

    const ctx = gsap.context(() => {
      // Header Animation
      gsap.from("[data-events-header]", {
        opacity: 0,
        y: 20,
        duration: 0.6,
        ease: "power2.out",
        scrollTrigger: {
          trigger: "[data-events-header]",
          start: "top 85%",
          once: true,
        },
      });

      // Cards Animation - Only run if cards exist
      const cards = gsap.utils.toArray<HTMLElement>("[data-event-card]");
      if (cards.length > 0) {
        cards.forEach((card, index) => {
          const isEven = index % 2 === 0;
          gsap.from(card, {
            opacity: 0,
            x: isEven ? -50 : 50,
            y: 30,
            duration: 0.8,
            ease: "power2.out",
            scrollTrigger: {
              trigger: card,
              start: "top 80%",
              once: true,
            },
          });
        });
      }
    }, sectionRef);

    return () => ctx.revert();
  }, []);

  // Fetch specifically 'published' events, limit 3
  const { data, isLoading, error } = useEvents(1, 3, "published");

  // Since API filters by status, we just use the data directly
  const publishedEvents = data?.data || [];

  return (
    <section
      ref={sectionRef}
      className="font-dm-sans overflow-hidden py-20 bg-[#F2F4F7]"
    >
      <div className="container mx-auto px-6 md:px-12 lg:px-20 2xl:px-20">
        {/* Header - Always Visible */}
        <div
          data-events-header
          className="flex flex-col md:flex-row md:items-end justify-between mb-12 gap-6"
        >
          <div className="max-w-2xl">
            <div className="inline-flex items-center gap-2 bg-[#ECFDF3] px-3 py-1 rounded-md text-sm font-semibold text-[#027A48] mb-4">
              <span className="w-1.5 h-1.5 rounded-full bg-[#027A48]"></span>
              Our Events
            </div>
            <h2 className="text-3xl md:text-5xl font-bold text-[#101828] leading-tight">
              Engagements That Strengthen Communities
            </h2>
          </div>
          <div className="shrink-0">
            <Link href="/events">
              <Button className="inline-block px-8 bg-green-700 hover:bg-green-800 text-white font-semibold rounded-lg transition-colors duration-300 shadow-sm hover:shadow-md">
                View All Events
              </Button>
            </Link>
          </div>
        </div>

        {/* Content Area */}
        {isLoading ? (
          <div className="text-center py-10">
            <div className="spinner border-t-4 border-green-700 border-solid w-10 h-10 rounded-full animate-spin mx-auto"></div>
          </div>
        ) : error ? (
          <div className="text-center py-10 text-red-500">
            Error: {error.message}
          </div>
        ) : publishedEvents.length === 0 ? (
          // ✅ Empty State
          <div className="text-center py-16 rounded-2xl border-gray-300">
            <p className="text-gray-500">No upcoming events found</p>
          </div>
        ) : (
          // ✅ Data Loaded - Events List
          <div className="space-y-8">
            {publishedEvents.map((event: EventType, index: number) => (
              <div
                key={event.id}
                data-event-card
                className={`bg-white rounded-2xl p-6 md:p-8 flex flex-col ${
                  index % 2 === 0 ? "lg:flex-row" : "lg:flex-row-reverse"
                } gap-8 items-center shadow-sm hover:shadow-md transition-shadow duration-300`}
              >
                {/* Image */}
                <div className="w-full lg:w-1/2 h-75 lg:h-90 relative rounded-xl overflow-hidden shrink-0">
                  <Image
                    src={
                      event.image || "/images/dashboard/memberApproval/1.jpg"
                    }
                    alt={`${event.title} - ${event.location}`}
                    fill
                    className="object-cover hover:scale-105 transition-transform duration-500"
                    sizes="(max-width: 1024px) 100vw, 50vw"
                    unoptimized={event.image?.startsWith("http")}
                  />
                </div>

                {/* Content */}
                <div className="w-full lg:w-1/2 flex flex-col justify-center">
                  <h3 className="text-2xl md:text-3xl font-bold text-[#101828] mb-4">
                    {event.title}
                  </h3>
                  <div
                    className="text-[#475467] text-base leading-relaxed mb-6 line-clamp-3 [&>p]:mb-0"
                    dangerouslySetInnerHTML={{ __html: event.description }}
                  />

                  {/* Meta Info & Button */}
                  <div className="flex flex-wrap gap-3 mb-8">
                    <div className="inline-flex items-center gap-2 bg-[#F2F4F7] px-3 py-1.5 rounded-full text-sm text-[#344054]">
                      <FormateDateTime
                        datetime={event.start_date}
                        type="date"
                        icon="calendar"
                      />
                    </div>
                    <div className="inline-flex items-center gap-2 bg-[#F2F4F7] px-3 py-1.5 rounded-full text-sm text-[#344054]">
                      <MapPin size={16} className="text-[#667085]" />
                      {event.location}
                    </div>
                    <div className="inline-flex items-center gap-2 bg-[#F2F4F7] px-3 py-1.5 rounded-full text-sm text-[#344054]">
                      <FormateDateTime
                        datetime={event.start_date}
                        type="time"
                        icon="clock"
                      />
                    </div>
                  </div>

                  <Link href={`/events/event-details/${event.id}`}>
                    <Button className="inline-block px-8 cursor-pointer py-3 bg-green-700 hover:bg-green-800 text-white text-[16px] font-semibold rounded-lg transition-colors duration-300 shadow-sm hover:shadow-md">
                      Learn More
                    </Button>
                  </Link>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </section>
  );
};

export default Events;
